using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change: HasIndex now throws for Cosmos entities.
        // Cosmos DB indexing is managed via the container's indexing policy, not EF Core.
        // modelBuilder.Entity<Blog>().HasIndex(b => b.Name);  // REMOVED

        // Breaking change: Default discriminator property renamed from "Discriminator" to "$type".
        // Preserve "Discriminator" so existing documents remain readable.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change: id format changed from "Blog|1" to just "1".
        // Preserve the old compound id format so existing documents remain accessible.
        modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

arguments.old_str:
class SyncJob
{
    void Run(BlogContext context)
    {
        var blogs = context.Blogs.ToList();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        context.SaveChanges();
    }
}

arguments.new_str:
class SyncJob
{
    // Breaking change: Cosmos DB provider no longer supports synchronous I/O.
    // ToList() and SaveChanges() throw; must use async equivalents.
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

